// 1. Dəyişənlər və Tiplər
public class VariablesExample {
  public static void main(String[] args) {
    int age = 25; // Tam ədəd
    double price = 99.99; // Onluq ədəd
    String name = "Alice"; // Sətir
    boolean isStudent = true; // Boolean
    System.out.println("Name: " + name + ", Age: " + age + ", Price: " + price + ", Student: " + isStudent);
  }
}
// Çıxış: Name: Alice, Age: 25, Price: 99.99, Student: true

// 2. Operatorlar
public class OperatorsExample {
  public static void main(String[] args) {
    int a = 10;
    int b = 5;
    int sum = a + b; // Toplama
    boolean isEqual = (a == b); // Müqayisə
    boolean andResult = (a > 0 && b > 0); // Məntiqi AND
    System.out.println("Sum: " + sum + ", Equal: " + isEqual + ", Both positive: " + andResult);
  }
}
// Çıxış: Sum: 15, Equal: false, Both positive: true

// 3. Şərtlər (if-else, switch)
public class ConditionsExample {
  public static void main(String[] args) {
    int age = 18;
    if (age >= 18) {
      System.out.println("You are an adult.");
    } else {
      System.out.println("You are a minor.");
    }

    int day = 1;
    switch (day) {
      case 1:
        System.out.println("Monday");
        break;
      case 2:
        System.out.println("Tuesday");
        break;
      default:
        System.out.println("Other day");
    }
  }
}
// Çıxış: You are an adult.
// Monday

// 4. Dövrlər (for, while, do-while)
public class LoopsExample {
  public static void main(String[] args) {
    // For dövrü
    for (int i = 1; i <= 5; i++) {
      System.out.println("Count: " + i);
    }
    // While dövrü
    int count = 1;
    while (count <= 3) {
      System.out.println("While count: " + count);
      count++;
    }
    // Do-while dövrü
    int num = 1;
    do {
      System.out.println("Do-while count: " + num);
      num++;
    } while (num <= 3);
  }
}
// Çıxış: Count: 1
// Count: 2
// Count: 3
// Count: 4
// Count: 5
// While count: 1
// While count: 2
// While count: 3
// Do-while count: 1
// Do-while count: 2
// Do-while count: 3

// 5. Metodlar
public class MethodsExample {
  public static String greet(String name) {
    return "Hello, " + name;
  }
  public static int add(int a, int b) {
    return a + b;
  }
  public static void main(String[] args) {
    String message = greet("Bob");
    int sum = add(10, 20);
    System.out.println(message + ", Sum: " + sum);
  }
}
// Çıxış: Hello, Bob, Sum: 30

// 6. Siniflər və Obyektlər
public class User {
  String name;
  int age;

  public User(String name, int age) {
    this.name = name;
    this.age = age;
  }

  public String getInfo() {
    return "Name: " + name + ", Age: " + age;
  }

  public static void main(String[] args) {
    User user = new User("Alice", 25);
    System.out.println(user.getInfo());
  }
}
// Çıxış: Name: Alice, Age: 25

// 7. Massivlər
public class ArraysExample {
  public static void main(String[] args) {
    int[] numbers = {1, 2, 3, 4, 5};
    String[] names = new String[2];
    names[0] = "Alice";
    names[1] = "Bob";

    for (int num : numbers) {
      System.out.println("Number: " + num);
    }
    System.out.println("First name: " + names[0]);
  }
}
// Çıxış: Number: 1
// Number: 2
// Number: 3
// Number: 4
// Number: 5
// First name: Alice

// 8. Sətirlər
public class StringsExample {
  public static void main(String[] args) {
    String text = "Hello, Java!";
    System.out.println("Length: " + text.length());
    System.out.println("Uppercase: " + text.toUpperCase());
    System.out.println("Contains 'Java': " + text.contains("Java"));
  }
}
// Çıxış: Length: 12
// Uppercase: HELLO, JAVA!
// Contains 'Java': true

public class Product {
  String id;
  String name;
  double price;

  public Product(String id, String name, double price) {
    this.id = id;
    this.name = name;
    this.price = price;
  }

  public String getInfo() {
    return "Product: " + name + ", ID: " + id + ", Price: " + price;
  }
}

public class Store {
  Product[] products;

  public Store(int capacity) {
    products = new Product[capacity];
  }

  public void addProduct(int index, String id, String name, double price) {
    if (index < products.length) {
      products[index] = new Product(id, name, price);
    }
  }

  public void printProducts() {
    for (Product product : products) {
      if (product != null) {
        System.out.println(product.getInfo());
      }
    }
  }

  public static void main(String[] args) {
    Store store = new Store(2);
    store.addProduct(0, "P001", "Laptop", 999.99);
    store.addProduct(1, "P002", "Phone", 499.99);
    store.printProducts();
  }
}
// Çıxış: Product: Laptop, ID: P001, Price: 999.99
// Product: Phone, ID: P002, Price: 499.99

